#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n,m; scanf("%d %d",&n,&m);
        char *unfinished = calloc(n+1,1);
        for(int i=1;i<=n;i++) unfinished[i]=1;
        for(int i=0;i<m;i++){
            int x; scanf("%d",&x);
            unfinished[x]=0;
        }
        int *rem = malloc(n*sizeof(int));
        int cnt=0;
        for(int i=1;i<=n;i++) if(unfinished[i]) rem[cnt++]=i;
        if(cnt==0){
            printf("-1\n-1\n");
        }else{
            // Chef
            for(int i=0;i<cnt;i+=2){
                if(i) printf(" ");
                printf("%d",rem[i]);
            }
            printf("\n");
            // Assistant
            if(cnt>1){
                for(int i=1;i<cnt;i+=2){
                    if(i>1) printf(" ");
                    printf("%d",rem[i]);
                }
                printf("\n");
            }else{
                printf("-1\n");
            }
        }
        free(unfinished);
        free(rem);
    }
    return 0;
}

