#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int n,m; cin>>n>>m;
        vector<char> ok(n+1,1);
        for(int i=0;i<m;i++){
            int x; cin>>x; ok[x]=0;
        }
        vector<int> rem; rem.reserve(n);
        for(int i=1;i<=n;i++) if(ok[i]) rem.push_back(i);
        if(rem.empty()){
            cout<<"-1\n-1\n";
            continue;
        }
        // Chef
        for(size_t i=0;i<rem.size();i+=2){
            if(i) cout<<' ';
            cout<<rem[i];
        }
        cout<<'\n';
        // Assistant
        if(rem.size()>1){
            bool first=true;
            for(size_t i=1;i<rem.size();i+=2){
                if(!first) cout<<' ';
                cout<<rem[i];
                first=false;
            }
            cout<<'\n';
        }else{
            cout<<"-1\n";
        }
    }
    return 0;
}

